import menuConfig from '../config/menuConfig.json';

/**
 * MenuService
 * 
 * Backend API와 통신하여 메뉴 데이터를 가져오는 역할을 담당합니다.
 * 현재는 설정 파일(menuConfig.json)에서 데이터를 가져오지만,
 * 추후 백엔드 API가 완성되면 fetch/axios 요청으로 대체할 수 있습니다.
 */
export const MenuService = {
    /**
     * 전체 메뉴 목록 조회
     * @returns {Promise<Array>} 메뉴 목록
     */
    getMenus: async () => {
        // 실제 API 호출 흉내 (Network delay simulation)
        return new Promise((resolve) => {
            setTimeout(() => {
                resolve(menuConfig.menus);
            }, 100);
        });
    }
};
